CREATE TABLE "Candidat" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "nom" varchar,
  "prenom" varchar,
  "parti_politique_id" integer,
  "popularite" float
);

CREATE TABLE "Resultats_Municipales" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "nom" varchar,
  "prenom" varchar,
  "nb_voix" integer,
  "num_tour" integer,
  "annee" integer,
  "candidat_id" integer
);

CREATE TABLE "Resultats_Presidentielles" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "nom" varchar,
  "prenom" varchar,
  "nb_voix" integer,
  "num_tour" integer,
  "annee" integer,
  "candidat_id" integer
);

CREATE TABLE "Parti_Politique" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "nom_parti" varchar,
  "bord" varchar
);

CREATE TABLE "Donnees_Angers" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "num_trimestre" int,
  "annee" int,
  "taux_chomage" float,
  "revenu_median" float,
  "taux_pauvrete" float,
  "taux_criminalite" float
);

ALTER TABLE "Candidat" ADD FOREIGN KEY ("parti_politique_id") REFERENCES "Parti_Politique" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "Resultats_Presidentielles" ADD FOREIGN KEY ("candidat_id") REFERENCES "Candidat" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "Resultats_Municipales" ADD FOREIGN KEY ("candidat_id") REFERENCES "Candidat" ("id") DEFERRABLE INITIALLY IMMEDIATE;
